import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Scheduling: High-Availability | Antigravity-Manager","description":"Learn Antigravity Manager scheduling: session_id generation, fixed account/sticky session/round-robin priority, rate limit marking, retry logic, and X-Account-Email verification.","frontmatter":{"title":"Scheduling: High-Availability | Antigravity-Manager","sidebarTitle":"Scheduling","subtitle":"Scheduling: High-Availability","description":"Learn Antigravity Manager scheduling: session_id generation, fixed account/sticky session/round-robin priority, rate limit marking, retry logic, and X-Account-Email verification.","tags":["Advanced","Scheduling","Sticky Session","Account Rotation","Failure Retry"],"prerequisite":["start-add-account","start-proxy-and-first-client","advanced-config"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/advanced/scheduling/index.md","filePath":"lbjlaq/Antigravity-Manager/advanced/scheduling/index.md"}'),s={name:"lbjlaq/Antigravity-Manager/advanced/scheduling/index.md"};function n(r,e,c,l,d,u){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="high-availability-scheduling-rotation-fixed-accounts-sticky-sessions-failure-retry" tabindex="-1">High-Availability Scheduling: Rotation, Fixed Accounts, Sticky Sessions &amp; Failure Retry <a class="header-anchor" href="#high-availability-scheduling-rotation-fixed-accounts-sticky-sessions-failure-retry" aria-label="Permalink to &quot;High-Availability Scheduling: Rotation, Fixed Accounts, Sticky Sessions &amp; Failure Retry&quot;">​</a></h1><p>After using Antigravity Tools as your local AI gateway for a while, you&#39;ll inevitably hit the same problem: fewer accounts means more frequent 429/401/invalid_grant errors, while more accounts makes it unclear &quot;which account is actually working,&quot; and cache hit rates drop.</p><p>This lesson clarifies scheduling: how it actually selects accounts, what &quot;sticky sessions&quot; means, when forced rotation happens, and how to use &quot;fixed account mode&quot; to make scheduling controllable.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand what Antigravity Tools&#39; 3 scheduling modes do in real requests</li><li>Know how &quot;session fingerprints (session_id)&quot; are generated and how they affect sticky scheduling</li><li>Enable/disable &quot;fixed account mode&quot; in the GUI and understand which scheduling logic it overrides</li><li>When encountering 429/5xx/invalid_grant, know how the system marks rate limits, retries, and when it rotates</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><ul><li>Claude Code or OpenAI SDK suddenly throws 429, and retrying switches accounts, causing cache hit rates to drop</li><li>Multiple clients running concurrent tasks often &quot;overwrite&quot; each other&#39;s account state</li><li>You want to troubleshoot but don&#39;t know which account is serving the current request</li><li>You want to use a specific &quot;most stable account&quot; but the system keeps rotating</li></ul><h2 id="when-to-use-this-guide" tabindex="-1">When to Use This Guide <a class="header-anchor" href="#when-to-use-this-guide" aria-label="Permalink to &quot;When to Use This Guide&quot;">​</a></h2><ul><li>You need to balance &quot;stability (fewer errors)&quot; against &quot;cache hits (same account)&quot;</li><li>You want the same conversation to reuse the same account as much as possible (reduce Prompt Caching jitter)</li><li>You&#39;re doing a canary release or troubleshooting and want to fix all requests to one account</li></ul><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><ol><li>Prepare at least 2 available accounts (smaller pool = less rotation space)</li><li>Reverse proxy service is running (you can see &quot;Running&quot; status on the &quot;API Proxy&quot; page)</li><li>You know where the config file is (if you need to manually modify configuration)</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you&#39;re not familiar with <code>gui_config.json</code> and which configs support hot reloading, read <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/advanced/config/">Config Deep Dive: AppConfig/ProxyConfig, Storage Location &amp; Hot Reload Semantics</a></strong> first.</p></div><h2 id="core-concepts-which-scheduling-layers-does-a-request-pass-through" tabindex="-1">Core Concepts: Which Scheduling Layers Does a Request Pass Through? <a class="header-anchor" href="#core-concepts-which-scheduling-layers-does-a-request-pass-through" aria-label="Permalink to &quot;Core Concepts: Which Scheduling Layers Does a Request Pass Through?&quot;">​</a></h2><p>Scheduling isn&#39;t a &quot;single switch&quot;—it&#39;s several mechanisms stacked together:</p><ol><li><strong>SessionManager first tags the request with a session fingerprint (session_id)</strong></li><li><strong>Handlers require TokenManager to force rotate on each retry</strong> (<code>attempt &gt; 0</code>)</li><li><strong>TokenManager then selects the account based on: fixed account → sticky session → 60s window → round-robin</strong></li><li><strong>When encountering 429/5xx, it records rate limit info</strong>, and subsequent scheduling actively skips rate-limited accounts</li></ol><h3 id="what-is-a-session-fingerprint-session-id" tabindex="-1">What Is a &quot;Session Fingerprint (session_id)&quot;? <a class="header-anchor" href="#what-is-a-session-fingerprint-session-id" aria-label="Permalink to &quot;What Is a &quot;Session Fingerprint (session_id)&quot;?&quot;">​</a></h3><p>A <strong>session fingerprint</strong> is a &quot;stable Session Key&quot; used to bind multiple requests in the same conversation to the same account.</p><p>In Claude requests, the priority is:</p><ol><li><code>metadata.user_id</code> (explicitly passed by client, non-empty, and without <code>&quot;session-&quot;</code> prefix)</li><li>Hash the first &quot;sufficiently long&quot; user message with SHA256, then truncate to <code>sid-xxxxxxxxxxxxxxxx</code></li></ol><p>Implementation: <code>src-tauri/src/proxy/session_manager.rs</code> (Claude/OpenAI/Gemini each have their own extraction logic).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>Detail</strong>: Why only look at the first user message?</p><p>The source code explicitly states &quot;hash only the first user message content, not mixing model name or timestamp,&quot; aiming to generate the same session_id for multiple rounds of the same conversation, thereby improving cache hit rates.</p></div><h3 id="tokenmanager-s-account-selection-priority" tabindex="-1">TokenManager&#39;s Account Selection Priority <a class="header-anchor" href="#tokenmanager-s-account-selection-priority" aria-label="Permalink to &quot;TokenManager&#39;s Account Selection Priority&quot;">​</a></h3><p>TokenManager&#39;s core entry point is:</p><ul><li><code>TokenManager::get_token(quota_group, force_rotate, session_id, target_model)</code></li></ul><p>What it does can be understood by priority:</p><ol><li><strong>Fixed Account Mode</strong>: If &quot;Fixed Account Mode&quot; is enabled in the GUI (runtime setting), and that account isn&#39;t rate-limited or quota-protected, use it directly.</li><li><strong>Sticky Session (Session Binding)</strong>: If there&#39;s a <code>session_id</code> and scheduling mode isn&#39;t <code>PerformanceFirst</code>, prioritize reusing the account bound to that session.</li><li><strong>60s Global Window Reuse</strong>: If no <code>session_id</code> passed (or not bound yet), in non-<code>PerformanceFirst</code> mode, try to reuse &quot;the last used account&quot; within 60 seconds.</li><li><strong>Round-robin</strong>: When none of the above apply, select accounts by a global incrementing index.</li></ol><p>Additionally, there are two &quot;invisible rules&quot; that significantly affect the experience:</p><ul><li><strong>Accounts are sorted first</strong>: ULTRA &gt; PRO &gt; FREE, with same tier prioritizing higher remaining quota accounts.</li><li><strong>Failed or rate-limited accounts are skipped</strong>: Already attempted failed accounts enter the <code>attempted</code> set; accounts marked as rate-limited are skipped.</li></ul><h3 id="what-s-the-real-difference-between-the-3-scheduling-modes" tabindex="-1">What&#39;s the Real Difference Between the 3 Scheduling Modes <a class="header-anchor" href="#what-s-the-real-difference-between-the-3-scheduling-modes" aria-label="Permalink to &quot;What&#39;s the Real Difference Between the 3 Scheduling Modes&quot;">​</a></h3><p>In the config you&#39;ll see: <code>CacheFirst</code> / <code>Balance</code> / <code>PerformanceFirst</code>.</p><p>Based on the actual backend TokenManager branches, their only key difference is: <strong>whether sticky sessions + 60s window reuse are enabled</strong>.</p><ul><li><code>PerformanceFirst</code>: Skips sticky sessions and 60s window reuse, goes directly to round-robin (while continuing to skip rate-limited/quota-protected accounts).</li><li><code>CacheFirst</code> / <code>Balance</code>: Both enable sticky sessions and 60s window reuse.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>About max_wait_seconds</strong></p><p>The frontend/config structure has <code>max_wait_seconds</code>, and the UI only allows adjusting it under <code>CacheFirst</code>. But currently, the backend scheduling logic only branches based on <code>mode</code> and doesn&#39;t read <code>max_wait_seconds</code>.</p></div><h3 id="how-failure-retry-forced-rotation-work-together" tabindex="-1">How Failure Retry &amp; &quot;Forced Rotation&quot; Work Together <a class="header-anchor" href="#how-failure-retry-forced-rotation-work-together" aria-label="Permalink to &quot;How Failure Retry &amp; &quot;Forced Rotation&quot; Work Together&quot;">​</a></h3><p>In OpenAI/Gemini/Claude handlers, retries are handled with a similar pattern:</p><ul><li>1st attempt: <code>force_rotate = false</code></li><li>2nd attempt onwards: <code>force_rotate = true</code> (<code>attempt &gt; 0</code>), TokenManager skips sticky reuse and directly finds the next available account</li></ul><p>When encountering 429/529/503/500 errors:</p><ul><li>The handler calls <code>token_manager.mark_rate_limited(...)</code> to record this account as &quot;rate-limited/overloaded,&quot; and subsequent scheduling actively skips it.</li><li>The OpenAI compatibility path also tries to parse <code>RetryInfo.retryDelay</code> or <code>quotaResetDelay</code> from error JSON, waits a short time, then continues retrying.</li></ul><h2 id="follow-along-make-scheduling-controllable" tabindex="-1">Follow Along: Make Scheduling &quot;Controllable&quot; <a class="header-anchor" href="#follow-along-make-scheduling-controllable" aria-label="Permalink to &quot;Follow Along: Make Scheduling &quot;Controllable&quot;&quot;">​</a></h2><h3 id="step-1-confirm-you-actually-have-an-account-pool" tabindex="-1">Step 1: Confirm You Actually Have an &quot;Account Pool&quot; <a class="header-anchor" href="#step-1-confirm-you-actually-have-an-account-pool" aria-label="Permalink to &quot;Step 1: Confirm You Actually Have an &quot;Account Pool&quot;&quot;">​</a></h3><p><strong>Why</strong> No matter how advanced the scheduling, if there&#39;s only 1 account in the pool, there&#39;s no choice. Many &quot;rotation not working/sticky doesn&#39;t feel like it&#39;s working&quot; root causes are too few accounts.</p><p><strong>Action</strong> Open the &quot;Accounts&quot; page and confirm at least 2 accounts are in an available state (not disabled / proxy disabled).</p><p><strong>What you should see</strong>: At least 2 accounts can refresh quota normally, and <code>active_accounts</code> is not 0 after the reverse proxy starts.</p><h3 id="step-2-choose-scheduling-mode-in-the-gui" tabindex="-1">Step 2: Choose Scheduling Mode in the GUI <a class="header-anchor" href="#step-2-choose-scheduling-mode-in-the-gui" aria-label="Permalink to &quot;Step 2: Choose Scheduling Mode in the GUI&quot;">​</a></h3><p><strong>Why</strong> Scheduling mode determines whether &quot;the same conversation&quot; reuses the same account as much as possible, or rotates each time.</p><p><strong>Action</strong> Go to the &quot;API Proxy&quot; page, find the &quot;Account Scheduling &amp; Rotation&quot; card, and select one mode:</p><ul><li><code>Balance</code>: Recommended default. More stable in most cases (sticky sessions + rotate on failure).</li><li><code>PerformanceFirst</code>: Choose this when concurrency is high, tasks are short, and you care more about throughput than caching.</li><li><code>CacheFirst</code>: Choose this if you want &quot;conversation to fix account as much as possible&quot; (current backend behavior differs very little from <code>Balance</code>).</li></ul><p>If you need to manually modify config, the corresponding segment is:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;proxy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scheduling&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Balance&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;max_wait_seconds&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">60</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>What you should see</strong>: After switching modes, it immediately writes to <code>gui_config.json</code>, and takes effect directly while the reverse proxy service is running (no restart needed).</p><h3 id="step-3-enable-fixed-account-mode-turn-off-rotation" tabindex="-1">Step 3: Enable &quot;Fixed Account Mode&quot; (Turn Off Rotation) <a class="header-anchor" href="#step-3-enable-fixed-account-mode-turn-off-rotation" aria-label="Permalink to &quot;Step 3: Enable &quot;Fixed Account Mode&quot; (Turn Off Rotation)&quot;">​</a></h3><p><strong>Why</strong> For troubleshooting, canary releases, or when you want to &quot;pin&quot; a specific account to a specific client, fixed account mode is the most direct approach.</p><p><strong>Action</strong> In the same card, enable &quot;Fixed Account Mode,&quot; then select an account in the dropdown.</p><p>Don&#39;t forget: This switch is only available when the reverse proxy service is Running.</p><p><strong>What you should see</strong>: Subsequent requests will prioritize using this account; if it&#39;s rate-limited or quota-protected, it will fall back to round-robin.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>Fixed account is a runtime setting</strong></p><p>Fixed account mode is a <strong>runtime state</strong> (set dynamically via GUI or API), not persisted to <code>gui_config.json</code>. After restarting the reverse proxy service, the fixed account will reset to empty (back to round-robin mode).</p></div><h3 id="step-4-clear-session-bindings-when-needed" tabindex="-1">Step 4: Clear &quot;Session Bindings&quot; When Needed <a class="header-anchor" href="#step-4-clear-session-bindings-when-needed" aria-label="Permalink to &quot;Step 4: Clear &quot;Session Bindings&quot; When Needed&quot;">​</a></h3><p><strong>Why</strong> Sticky sessions record <code>session_id -&gt; account_id</code> in memory. If you&#39;re doing different experiments on the same machine (like switching account pools, switching modes), old bindings might interfere with your observations.</p><p><strong>Action</strong> Click &quot;Clear bindings&quot; in the top-right of the &quot;Account Scheduling &amp; Rotation&quot; card.</p><p><strong>What you should see</strong>: Old sessions will be reassigned accounts (next request will rebind).</p><h3 id="step-5-use-response-headers-to-verify-which-account-is-serving" tabindex="-1">Step 5: Use Response Headers to Verify &quot;Which Account Is Serving&quot; <a class="header-anchor" href="#step-5-use-response-headers-to-verify-which-account-is-serving" aria-label="Permalink to &quot;Step 5: Use Response Headers to Verify &quot;Which Account Is Serving&quot;&quot;">​</a></h3><p><strong>Why</strong> To verify scheduling matches expectations, the most reliable way is to get the &quot;current account identifier&quot; returned by the server.</p><p><strong>Action</strong> Send a non-streaming request to an OpenAI-compatible endpoint, then observe <code>X-Account-Email</code> in response headers.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example: Minimal OpenAI Chat Completions request</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Note: model must be an available/routable model name in your current config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:8045/v1/chat/completions&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_ME&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;gemini-3-pro-high&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;stream&quot;: false,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;hello&quot;}]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><p><strong>What you should see</strong>: Response headers will appear similar to below (example):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>X-Account-Email: example@gmail.com</span></span>
<span class="line"><span>X-Mapped-Model: gemini-3-pro-high</span></span></code></pre></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>You can clearly explain the priority relationship between <code>fixed account</code>, <code>sticky session</code>, and <code>round-robin</code></li><li>You know how <code>session_id</code> is generated (prioritize <code>metadata.user_id</code>, otherwise hash first user message)</li><li>When encountering 429/5xx, you can expect: the system will first record rate limiting, then switch accounts and retry</li><li>You can use <code>X-Account-Email</code> to verify which account is serving the current request</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><ol><li><p><strong>Don&#39;t expect &quot;rotation to save you&quot; when the account pool only has 1</strong> Rotation only means &quot;switch to another account&quot;—when there&#39;s no second account in the pool, 429/invalid_grant will be exposed even more frequently.</p></li><li><p><strong><code>CacheFirst</code> is not &quot;wait until available forever&quot;</strong> Current backend scheduling logic tends to unbind and switch accounts when encountering rate limits, rather than blocking and waiting long-term.</p></li><li><p><strong>Fixed account is not absolute force</strong> If the fixed account is marked as rate-limited or hit by quota protection, the system will fall back to round-robin.</p></li></ol><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><ul><li>Scheduling flow: handler extracts <code>session_id</code> → <code>TokenManager::get_token</code> selects account → on error <code>attempt &gt; 0</code> forces rotation</li><li>Your two most commonly used switches: scheduling mode (whether to enable sticky/60s reuse) + fixed account mode (directly specify account)</li><li>429/5xx are recorded as &quot;rate-limited state,&quot; subsequent scheduling will skip that account until the lock expires</li></ul><h2 id="coming-next" tabindex="-1">Coming Next <a class="header-anchor" href="#coming-next" aria-label="Permalink to &quot;Coming Next&quot;">​</a></h2><blockquote><p>Next lesson we look at <strong>model routing</strong>: when you want to expose &quot;stable model sets&quot; externally, and want to use wildcard/preset strategies, how to configure and troubleshoot.</p></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Scheduling mode and config structure (StickySessionConfig)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L1-L36" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>1-36</td></tr><tr><td>Session fingerprint generation (Claude/OpenAI/Gemini)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/session_manager.rs#L1-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/session_manager.rs</code></a></td><td>1-159</td></tr><tr><td>TokenManager: Fixed account mode fields and initialization</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L27-L50" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>27-50</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>TokenManager: Rate limit recording and success clearing API</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1087-L1147" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1087-1147</td></tr><tr><td>TokenManager: Update scheduling config / Clear session bindings / Fixed account mode setter</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1419-L1461" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1419-1461</td></tr><tr><td>ProxyConfig: scheduling field definition and defaults</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L257" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-257</td></tr><tr><td>Sync scheduling config when reverse proxy starts</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/proxy.rs#L70-L100" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/proxy.rs</code></a></td><td>70-100</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>OpenAI handler: session_id + force rotate on retry</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L160-L182" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>160-182</td></tr><tr><td>OpenAI handler: 429/5xx record rate limit + parse retry delay</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L367" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-367</td></tr><tr><td>Gemini handler: session_id + force rotate on retry</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L62-L88" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>62-88</td></tr><tr><td>Gemini handler: 429/5xx record rate limit and rotate</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L279-L299" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>279-299</td></tr><tr><td>Claude handler: extract session_id and pass to TokenManager</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L517-L524" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>517-524</td></tr><tr><td>429 retry delay parsing (RetryInfo.retryDelay / quotaResetDelay)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L37-L66" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>37-66</td></tr><tr><td>Rate limit cause identification and exponential backoff (RateLimitTracker)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L154-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>154-279</td></tr></tbody></table><p><strong>Key Structures</strong>:</p><ul><li><code>StickySessionConfig</code>: Scheduling mode and config structure (<code>mode</code>, <code>max_wait_seconds</code>)</li><li><code>TokenManager</code>: Account pool, session bindings, fixed account mode, rate limit tracker</li><li><code>SessionManager</code>: Extract <code>session_id</code> from requests</li></ul></details>`,77)])])}const g=t(s,[["render",n]]);export{p as __pageData,g as default};
